(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn10"],{"01dd":function(n,r,t){"use strict";t.r(r);var a=function(){var n=this,r=n.$createElement,a=n._self._c||r;return a("markdown",{attrs:{source:t("6887")}})},i=[],e=t("2877"),o={},l=Object(e["a"])(o,a,i,!1,null,null,null);l.options.__file="go.vue";r["default"]=l.exports},6887:function(n,r){n.exports='## Go学习总结\r\n\r\n### 安装\r\n到golang官网下载，安装。\r\n```\r\nhttps://studygolang.com/dl\r\n```\r\n\r\n```s\r\n # 安装terminal插件后，按住shift+command+t即可快速打开当前文件夹的终端\r\n 按住shift+command+t即可快速打开当前文件夹的终端\r\n # 执行\r\n go run <要执行的文件>\r\n```\r\n\r\nvscode安装go插件一直失败，以下为网上找到的方法，亲测可用 (https://www.jianshu.com/p/be432e57acd2)\r\n```\r\n1、在%GOPATH%\\src\\ 目录下，建立golang.org 文件夹，并再新建x文件夹。 目录为 "%GOPATH\\src\\golang.org\\x"\r\n2、完成目录切换后，开始下载插件包：git clone https://github.com/golang/tools.git tools\r\n3、执行完以后，会多一个tools文件夹\r\n4、打开vsCode终端，切换到 终端，进入“%GOPATH”目录,执行:\r\ngo install github.com/ramya-rao-a/go-outline\r\ngo install github.com/acroca/go-symbols\r\ngo install golang.org/x/tools/cmd/guru\r\ngo install golang.org/x/tools/cmd/gorename\r\ngo install github.com/josharian/impl\r\ngo install github.com/rogpeppe/godef\r\ngo install github.com/sqs/goreturns\r\ngo install github.com/golang/lint/golint\r\ngo install github.com/cweill/gotests/gotests\r\n```\r\ngolang.org/x/net 安装方法(其它 golang.org/x 下的包获取皆可使用该方法)\r\n```\r\n$mkdir -p $GOPATH/src/golang.org/x/\r\n$cd $GOPATH/src/golang.org/x/\r\n$git clone https://github.com/golang/net.git net\r\n$go install net\r\n```\r\n\r\n### 变量定义\r\n```go\r\npackage main\r\n\r\nimport "fmt"\r\n\r\n/*\r\n＊ 在函数外边必须用va\br定义变量，用:=定义变量会报错。\r\n＊ 在函数外定义的变量不是全局变量，它在这个包内有效。\r\nvar aa = 3\r\nvar ss = "kkk"\r\n// bb := true  //会报错\r\n*/\r\nvar (\r\n  aa = 3\r\n  ss = "kkk"\r\n  bb = true\r\n)\r\n\r\nfunc variableZeroValue() {\r\n  var a int\r\n  var s string\r\n  fmt.Printf("%d %q\\n", a, s)\r\n  fmt.Println("-----------------")\r\n}\r\n\r\nfunc variableInitialValue() {\r\n  var a, b int = 3, 4\r\n  var s string = "abc"\r\n  fmt.Println(a, b, s)\r\n  fmt.Println("-----------------")\r\n}\r\n\r\nfunc variableTypeDeduction() {\r\n  var a, b, c, s = 3, 4, true, "def"\r\n  fmt.Println(a, b, c, s)\r\n  fmt.Println("-----------------")\r\n}\r\n\r\nfunc variableShorter() {\r\n  // 定义变量可以用:=,尽量少使用var来定义变量\r\n  a, b, c, s := 3, 4, true, "def"\r\n  fmt.Println(a, b, c, s)\r\n  fmt.Println("-----------------")\r\n}\r\n\r\nfunc main() {\r\n  fmt.Println("Hello World")\r\n  variableZeroValue()\r\n  variableInitialValue()\r\n  variableTypeDeduction()\r\n  variableShorter()\r\n  fmt.Println(aa,ss,bb)\r\n}\r\n\r\n/*\r\n输出:\r\nHello World\r\n0 ""\r\n-----------------\r\n3 4 abc\r\n-----------------\r\n3 4 true def\r\n-----------------\r\n3 4 true def\r\n-----------------\r\n3 kkk true\r\n*/\r\n```\r\n\b小结\r\n```\r\n使用var关键字\r\n  var a,b,c bool\r\n  var s1,s2 string = "hello", "world"\r\n  可放在函数内，或者直接放在包内\r\n  使用var()集中定义变量\r\n让编译器自动决定类型\r\n  var a,b,i,s1,s2 = true,false,3,"hello","world"  \r\n使用:=定义变量\r\n  a,b,i,s1,s2 := true,false,3,"hello","world"  \r\n  只能在函数内使用\r\n```\r\n\r\n### 内置变量类型\r\n\r\ngo的内置变量类型\r\n```\r\nbool, string;\r\n(u)int, (u)int8, (u)int16, (u)int32, (u)int64, uintptr;\r\nbyte, rune\r\nfloat32, float64, complex64, complex128.\r\n\r\n其中(u)int的位数由操作系统决定；\r\nuintptr是指针；\r\nbyte和rune是int的别名，byte是8位rune是32位；\r\ncomplex64的实部和虚部都是float32，complex128的实部和虚部都是float64。\r\n```\r\n\r\n```\r\n类型        长度     说明\r\nbool         1      true/false,默认false, 不能把非0值当做true(不用数字代表true/false)\r\nbyte         1      uint8 别名\r\nrune         4      int32别名。 代表一个unicode code point\r\nint/unit            一来所运行的平台，32bit/64bit\r\nint8/uint8   1     -128 ~ 127; 0 ~ 255\r\nint16/uint16 2     -32768 ~ 32767; 0 ~ 65535\r\nint32/uint32 4     -21亿 ~ 21亿， 0 ~ 42亿\r\nint64/uint64 8\r\n\r\nfloat32      4     精确到7位小数,相当于c的float\r\nfloat64      8     精确到15位小数,相当于c的double\r\n\r\ncomplex64    8\r\ncomplex128   16\r\n\r\nuintptr            足够保存指针的32位、64位整数,指针(可以存指针的整数型)\r\narray              值类型,数组\r\nstruct             值类型,结构体\r\nstring             值类型,字符串类型，常用\r\nslice              引用类型,切片\r\nmap                引用类型,字典\r\nchannel            引用类型,通道\r\ninterface          接口类型,接口\r\nfunction           函数类型,函数\r\n```\r\n ```go\r\n package main\r\n\r\nimport (\r\n\t"fmt"\r\n\t"math"\r\n\t"math/cmplx"\r\n)\r\n\r\nfunc euler() {\r\n  // 复数\r\n  c := 3 + 4i\r\n  fmt.Println(cmplx.Abs(c))\r\n  //最美欧拉公式\r\n  fmt.Println(cmplx.Pow(math.E, 1i*math.Pi) + 1)\r\n  fmt.Printf("%.3f", cmplx.Exp(1i*math.Pi) + 1)\r\n}\r\n\r\nfunc main() {\r\n  euler() \r\n}\r\n/*\r\n输出:\r\n5\r\n(0+1.2246467991473515e-16i)\r\n(0.000+0.000i)\r\n */\r\n ```\r\n 强制类型转换\r\n ```go\r\nfunc triangle() {\r\n\tvar a, b int = 3, 4\r\n\tvar c int\r\n\tc = int(math.Sqrt(float64(a*a + b*b)))\r\n\tfmt.Println(c)\r\n}\r\n// 5\r\n ```\r\n\r\n### 常量和枚举\r\n\r\n```go\r\n// 常量\r\nfunc consts() {\r\n  const (\r\n    filename = "abc.txt"\r\n    a, b = 3, 4\r\n  )\r\n  var c int\r\n  c = int(math.Sqrt(a*a + b*b))\r\n  fmt.Println(filename, c)\r\n}\r\n// 枚举\r\nfunc enums() {\r\n  const (\r\n    cpp    = 0\r\n    java   = 1\r\n    python = 2\r\n    golang = 3\r\n  )\r\n  fmt.Println(cpp, java, python, golang)\r\n}\r\n// iota 自增值\r\nfunc enums() {\r\n  const (\r\n    cpp = iota\r\n    java\r\n    python\r\n    golang\r\n  )\r\n  const (\r\n    b = 1 << (10 * iota)\r\n    kb\r\n    mb\r\n    gb\r\n    tb\r\n    pb\r\n  )\r\n  fmt.Println(cpp, java, python, golang)\r\n  fmt.Println(b, kb, mb, gb, tb, pb)\r\n}\r\n```\r\n小结：\r\n```\r\n变量类型写在变量名之后\r\n编译器可以推测变量类型\r\n没有char, 只有rune\r\n原生支持复数类型\r\n```\r\n\r\n### 条件语句\r\nif\r\n```go\r\n  if contents, err := ioutil.ReadFile(filename); err != nil {\r\n   fmt.Println(err)\r\n  } else {\r\n    fmt.Printf("%s\\n", contents)\r\n  }\r\n```\r\n等同于\r\n```go\r\n  contents, err := ioutil.ReadFile(filename); \r\n  if err != nil {\r\n   fmt.Println(err)\r\n  } else {\r\n    fmt.Printf("%s\\n", contents)\r\n  }\r\n```\r\nswitch\r\n```go\r\nfunc switchTest(a, b int, op string) int {\r\n  var result int\r\n  switch op {\r\n  case "+":\r\n    result = a + b\r\n  case "-":\r\n    result = a - b\r\n  case "*":\r\n    result = a * b\r\n  case "/":\r\n    result = a / b\r\n  default:\r\n    panic("unsupported operator:" + op)\r\n  }\r\n  return result\r\n}\r\n---------------------------------------------------\r\nfunc switchTest2(score int) string {\r\n  g := ""\r\n  switch {\r\n  case score < 0 || score > 100:\r\n    panic(fmt.Sprintf("Wrong score: %d", score))\r\n  case score < 60:\r\n    g = "F"\r\n  case score < 80:\r\n    g = "C"\r\n  case score < 90:\r\n    g = "B"\r\n  case score < 100:\r\n    g = "A"\r\n  }\r\n  return g\r\n}\r\n```\r\n+ 当出现不等于nil的时候，说明出现某些错误了，需要我们对这个错误进行一些处理，而如果等于nil说明运行正常。那什么是nil呢？查一下词典可以知道，nil的意思是无，或者是零值。零值，zero value，是不是有点熟悉？在Go语言中，如果你声明了一个变量但是没有对它进行赋值操作，那么这个变量就会有一个类型的默认零值。这是每种类型对应的零值\r\n```go\r\nbool  -> false                              \r\nnumbers -> 0                                 \r\nstring    -> ""      \r\n\r\npointers -> nil\r\nslices -> nil\r\nmaps -> nil\r\nchannels -> nil\r\nfunctions -> nil\r\ninterfaces -> nil\r\n```\r\n\r\nfor\r\n```go\r\nfunc printFile(filename string) {\r\n  if file, err := os.Open(filename); err != nil {\r\n    panic(err)\r\n  } else {\r\n    scanner := bufio.NewScanner(file)\r\n    for scanner.Scan() {\r\n      fmt.Println(scanner.Text())\r\n    }\r\n  }\r\n}\r\n```\r\n小结\r\n```s\r\nfor,if 后边的条件没有括号\r\nif条件里也可以定义变量\r\n没有while\r\nswitch不需要break，也可以直接switch多个条件\r\n```\r\n\r\n### 函数\r\n```go\r\nfunc div(a, b int) (q, r int) {\r\n  return a / b, a % b\r\n}\r\n\r\n\r\nfunc evel(a, b int, op string) (int, error) {\r\n  switch op {\r\n  case "+":\r\n    return a + b, nil\r\n  case "-":\r\n    return a - b, nil\r\n  case "*":\r\n    return a * b, nil\r\n  case "/":\r\n    return a / b, nil\r\n  default:\r\n    return 0, fmt.Errorf(\r\n      "unsupported operation: %s", op)\r\n  }\r\n}\r\n\r\nfunc pow(a, b int) int {\r\n  return int(math.Pow(float64(a), float64(b)))\r\n}\r\nfunc apply(op func(int, int) int, a, b int) int {\r\n  p := reflect.ValueOf(op).Pointer()\r\n  opName := runtime.FuncForPC(p).Name()\r\n  fmt.Printf("Calling function %s with args"+"(%d,%d)\\n", opName, a, b)\r\n  return op(a, b)\r\n}\r\n// fmt.Println(apply(pow, 3, 4))\r\n// Calling function main.pow with args(3,4)\r\n// 81\r\n\r\nfunc sum(numbers ...int) int {\r\n  s := 0\r\n  for i := range numbers {\r\n    s += numbers[i]\r\n  }\r\n  return s\r\n}\r\n```\r\n小结\r\n```\r\n返回值类型写在最后边\r\n可返回多个值\r\n函数作为参数\r\n没有默认参数，可选参数\r\n```\r\n\r\n###  指针\r\n```go\r\nvar a int =2\r\nvar pa *int = &a\r\n*pa = 3\r\nfmt.Println(a) // 3\r\n```\r\n指针不能运算\r\n值传递？引用传递？\r\n\r\n```go\r\nfunc swap(a, b int) {\r\n  b, a = a, b\r\n}\r\n// a, b := 3, 4\r\n// swap(a,b)\r\n// fmt.Println(a, b)  // 3,4\r\n\r\nfunc swap(a, b *int) {\r\n  *b, *a = *a, *b\r\n}\r\n// a, b := 3, 4\r\n// swap(&a,&b)\r\n// fmt.Println(a, b)  // 4,3\r\n\r\nfunc swap(a, b int) (int, int){\r\n  return b, a\r\n}\r\n// a, b := 3, 4\r\n// a, b := swap(a,b)\r\n// fmt.Println(a, b)  // 4,3\r\n```\r\n\r\n### 数组\r\n```go\r\nfunc printArray(arr [5]int) {\r\n  for i, v := range arr {\r\n    fmt.Println(i, v)\r\n  }\r\n}\r\n\r\nfunc arrTest() {\r\n  var arr1 [5]int\r\n  arr2 := [3]int{1, 3, 5}\r\n  arr3 := [...]int{2, 4, 6, 8, 10}\r\n  var grid [4][5]int\r\n  fmt.Println(arr1, arr2, arr3, grid)\r\n  for i := 0; i < len(arr3); i++ {\r\n    fmt.Println(arr3[i])\r\n  }\r\n  for i, v := range arr3 {\r\n    fmt.Println(i, v)\r\n  }\r\n  for _, v := range arr3 {\r\n    fmt.Println(v)\r\n  }\r\n  printArray(arr1)\r\n  printArray(arr3)\r\n}\r\n```\r\n数组是值类型\r\n```go\r\n[10]int和[20]int是不同类型\r\n调用func f(arr [10]int) 会拷贝数组\r\n在go语言中一般不直接使用数组，一般使用切片\r\n```\r\n\r\n### 切片（Slice）\r\n![](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/go/slice_nbjg.jpg)\r\n\r\n![](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/go/slices.jpg)\r\n```s\r\nSlice的内部：\r\nptr，指向slice开头的元素，\r\nlen，说明slice的长度，方括号取值时只能取到length里面的值，下标超出就报错，\r\ncap（capacity：容量），从ptr开始到结束的整个array的长度；\r\n【这是Slice内部的三个变量】扩展时，只要不超过capacity就可以扩展，只能向后扩展；\r\ncap(s)：Slice的容量，  len(s)：Slice的长度\r\n```\r\n![](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/go/slice_aaa.jpg)\r\n![](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/go/slece_desc.jpg)'}}]);